var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":" 전 소대, 배치 완료.","JPN":" 全小隊、配置完了。","ENG":"All units, in formation.","TWN":"所有小隊佈署完畢。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":" 카운터들도 지정된 위치에서 대기 중입니다.","JPN":" カウンターたちも指定の場所で待機しています。","ENG":"The Counters are standing by in their designated positions.","TWN":"制裁者也都就指定位置待命。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 좋아. 곧 요인이 승강기를 타고 내려올 거다. ","JPN":" よし、もうすぐ要人がエレベーターで降りてくる。 ","ENG":"Good. The VIP will soon come down via the elevator.","TWN":"很好，VIP馬上就會搭電梯下來。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 전원 임무 중 긴장을 놓지 마라. 도시 한복판이라고 방심하지 말고.","JPN":" 全員任務中は気を抜くな。街のど真ん中とはいえ油断は禁物だ。","ENG":"All units are to stay vigilant during the mission. And do not let your guard down just because it is an urban area.","TWN":"大家值勤中保持戒備，這裡可是市中心，不能大意。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":" 그나저나 안타깝네요. 슈나이더 부인 말이에요.","JPN":" それにしても気の毒でしたね。シュナイダー夫人。","ENG":"I mean, it's a shame, with Mrs. Schneider.","TWN":"不過修奈德夫人還真可憐。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":" 그림자들이 노리다니……. 저 같으면 하루하루가 악몽 같겠어요.","JPN":" シャドウに狙われるなんて……私なら毎日が地獄だったでしょう。","ENG":"To be hunted down by Shadows... Every day would feel like a nightmare if it were me.","TWN":"暗影竟然想對她下手……要是我應該每天都像活在惡夢裡吧。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" ……어, 음? 방금 누가 지나가지 않았어?","JPN":" ……え、うむ？　今誰か通らなかったか？","ENG":"...Hmm? Did someone just pass by?","TWN":"……嗯？剛剛是不是有人經過？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":" 네? 지나가다니요?","JPN":" はい？　通るって、何がですか？","ENG":"Huh? Who passed by?","TWN":"有嗎？誰經過？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 아니야. 내가 뭔가 착각했나 봐.","JPN":" いや、なんでもない。気のせいだったようだ。","ENG":"Never mind. I guess I'm seeing things.","TWN":"沒有啦，應該是我眼花。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 그보다 잠깐 기다려.","JPN":" それより少し待て。","ENG":"But wait a second.","TWN":"你先等我一下。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":" 네? 왜 그러세요?","JPN":" はい？　どうされました？","ENG":"Yes? What's the matter?","TWN":"怎麼了嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 기껏 한다는 게 늙은이 뒷바라지라니까 갑자기 살기가 싫어져서.","JPN":" ご老人の後始末なんかやらされる人生だと思ったら死にたくなった。","ENG":"I don't want to live anymore taking care of some old hag.","TWN":"一直在做些看護的事，突然覺得不想活了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":" ……아. 그렇네요.","JPN":" ……確かに、そうですね。","ENG":"...Ah. I agree.","TWN":"……也是。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":" 열심히 일해 봤자 침식체는 계속 나타나고 월급을 모아도 길어야 백 년 살고 죽을 텐데.","JPN":" いくら頑張って働いたって侵食体はいなくなりませんし、いくら給料があっても100年ぐらいでどうせ死にますし。","ENG":"Hard work won't stop the C.O.s from coming, and I'm not going to live past 100 with this salary.","TWN":"努力工作侵蝕體還是一直出現，就算把薪水都存起來，長壽一點的話還要活到一百歲。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":" 잠깐 위에 갔다 올게요. 머리부터 먼저 떨어지면 3층에서 추락해도 충분하겠죠.","JPN":" ちょっと上に行ってきます。頭から落ちれば3階でも十分死ねますよね。","ENG":"I'm going to go upstairs. The third floor should be enough if I fall head first.","TWN":"我上去一下，頭先著地的話，從三樓跳下來應該也必死無疑吧。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":" 누구세요……?","JPN":" どちら様でしょうか……？","ENG":"Who are you...?","TWN":"是誰……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 접니다, 부인.","JPN":" 私です、シュナイダー夫人。","ENG":"It's me, Mrs. Schneider.","TWN":"夫人，是我。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 하하, 오늘도 팬케이크를 구우셨군요. 냄새 좋네요.","JPN":" はは、今日もパンケーキを焼いてくださったんですか。良い匂いがしますね。","ENG":"Ha ha, you made pancakes again. They smell delicious.","TWN":"哈哈，你今天也有做鬆餅嗎？好香喔。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":" 그럼요. 이거라도 만들어 드려야죠. 저 때문에 많은 분들이 고생하시는데.","JPN":" ええ。これは私なりの誠意なのよ。皆さんが私のせいで苦労されていますから。","ENG":"Of course. It's the least I can do when I'm being such a nuisance to everyone.","TWN":"是啊，這是我應該做的，畢竟大家為了我這麼辛苦。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":" 오랫동안 만들지 않아서……. 다들 입맛에 맞으실지는 모르겠어요.","JPN":" でもずいぶん長いこと作っていなかったもので……皆さんのお口に合うといいのだけれど。","ENG":"I haven't made pancakes in a while... so I'm not sure if everyone will like them.","TWN":"但我很久沒做了……不知道合不合大家的胃口。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 설마요. 다른 팀들에도 소문날 만큼 호평입니다.","JPN":" いいえ、他のチームでも噂になっているほど大好評ですよ。","ENG":"Nonsense! It's so great that the other teams are talking about it too.","TWN":"當然囉，其他隊的人也都說好吃呢。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 그보다 부인, 오늘부터는 여기보다 훨씬 좋은 호텔에서 지내시게 될 겁니다.","JPN":" それより夫人、今日からこことは比べ物にならないぐらい良いホテルに移ることになりましたよ。","ENG":"On a different note, Mrs. Schneider, you'll be staying at a much better hotel starting today.","TWN":"不過夫人，從今天開始要請你搬到更好的飯店去住。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":" 제가 여기 없으면 중사님이 걱정하실 텐데…….","JPN":" 私がここからいなくなったら、軍曹さんが心配するんじゃないかしら……","ENG":"But, the sergeant will worry if I'm not here...","TWN":"可是我不在這裡的話中士會擔心的……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 걱정 마세요. 브레히트 중사 일행에게는 따로 연락이 갈 겁니다.","JPN":" 心配はいりません。ブレヒト軍曹の御一行には別途連絡が行きますから。","ENG":"Don't worry. We will contact Sergeant Brecht too.","TWN":"夫人請放心，我們會另外通知布萊希特中士的。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":" 그래요……? ","JPN":" そう……？ ","ENG":"Is that so...?","TWN":"是嗎……？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 네. 그러니 어서 가시죠. 부인을 경호하기 위해 카운터들까지 여럿 소집됐습니다.","JPN":" はい、ですからさっそく出発しましょう。夫人を警護するためにカウンターも数人招集されています。","ENG":"Yes. Now, let us go. Even Counters were called in to escort you, Mrs. Schneider.","TWN":"是的，我們趕緊出發吧。為了保護夫人，我們還召集了幾位制裁者呢。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 소대장님, 슈나이더 부인을 모시고 왔습니다.","JPN":" 小隊長、シュナイダー夫人をお連れしました。","ENG":"Commander, we brought Mrs. Schneider.","TWN":"小隊長，我把修奈德女士帶來了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 응? 다들 어디 간 거야?","JPN":" うん？　なんで誰もいないんだ？","ENG":"Huh? Where did everyone go?","TWN":"嗯？大家跑哪去了？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":" 바, 방금...... 창밖으로 사람들이......","JPN":" い、今……窓の外から人が……","ENG":"I-I just saw... people jumping out the...","TWN":"剛…剛窗戶外…有人掉…"},"stage":{"bg":"HALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 부인, 보시면 안 됩니다!","JPN":" 夫人、見てはいけません！","ENG":"Look away, Mrs. Schneider!","TWN":"夫人別看！"},"stage":{"bg":"HALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":" 아. 거기 있었구나.","JPN":" あら、そこにいたのね。","ENG":"Ah. There you are.","TWN":"原來在這裡。"},"stage":{"bg":"HARMONY2_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":" 안녕. 그리고 다시 안녕.","JPN":" こんにちは。それから、さようなら。","ENG":"Hello. And goodbye.","TWN":"你好，再見。"},"stage":{"bg":"HARMONY2_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":" 기다리는 동안 너희 친구들에게 연주를 들려 줬어.","JPN":" あなたたちを待っている間に、お友達に演奏を聞かせてあげていたの。","ENG":"I played music for your friends while I was waiting.","TWN":"我在等你們的時候，有為你的夥伴演奏。"},"stage":{"bg":"HARMONY2_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":" 내 연주는 우울해서 다들 듣기 싫어하니까, 몰래.","JPN":" 私の演奏は暗くてみんな聞きたがらないから、こっそりね。","ENG":"Secretly, since everyone hates how depressing my music is.","TWN":"我的演奏有點憂鬱，大家好像都不想聽的樣子。"},"stage":{"bg":"HARMONY2_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 그, 그림자......?!","JPN":" しゃ、シャドウ……！？","ENG":"A-a Shadow...?!","TWN":"你是，暗影……？！"},"stage":{"bg":"HARMONY2_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":" 그 아이가...... 레아가 저를 데려오라고 했나요?","JPN":" あの子が……レアが私を連れてくるように言ったんですか？","ENG":"Did the child... Did Leah tell you to bring me?","TWN":"是那孩子……是蕾亞要你來接我的嗎？"},"stage":{"bg":"HARMONY2_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":" 응. 최고 지휘자님은 아이라기엔 많이 크지만.","JPN":" ええ、マエストロは「子」と呼ぶにはだいぶ年齢がいっているけれど。","ENG":"Yes. Our Chief Conductor is quite big to be called a child, however.","TWN":"嗯，雖然首席指揮家離孩子這個稱呼有點遙遠。"},"stage":{"bg":"HARMONY2_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":" 너무 무서워하지 마. 죽음은 순간일 뿐이니까.","JPN":" あんまり怖がらないで。死ぬのは一瞬だから。","ENG":"Don't be scared. Death is but a moment.","TWN":"不用怕，死亡不過是一瞬間的事。"},"stage":{"bg":"HARMONY2_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":" 여기 목을 매단 사람들을 봐. 모두 편안해 보이지 않니?","JPN":" ここの首吊りした人たちを見て。みんなすごく安らかに見えるでしょう？","ENG":"Look at all the people who hung themselves. Don't they look so tranquil?","TWN":"你看看這些脖子斷掉的人，是不是全都看起來很安詳？"},"stage":{"bg":"HARMONY2_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":" 죽으면 혀를 빼물고, 머릿속의 내용물을 아무데나 쏟아내도 뭐라 하는 사람이 없거든.","JPN":" 死んだら舌を垂らしたり、頭の中身を所構わずぶちまけたりしても文句を言う人は一人もいないもの。","ENG":"When you are dead, no one will blame you for sticking your tongue out or spilling your brains on the floor.","TWN":"就算舌頭吐出來，腦漿噴出來，也不會有人在旁邊指指點點。"},"stage":{"bg":"HARMONY2_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":" 너희도 곧 그렇게 될 거야.","JPN":" あなたたちももうすぐそうなるわ。","ENG":"And that will be all of your futures as well.","TWN":"你們很快也會變得跟他們一樣。"},"stage":{"bg":"HARMONY2_02","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":" 응……? 지진?","JPN":" ん……？　地震？","ENG":"Hmm...? An earthquake...?","TWN":"嗯……？地震？"},"stage":{"bg":"HALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 어, 엎드리세요! 부인!","JPN":" ふ、伏せてください！　夫人！","ENG":"Mrs. Schneider! D-duck!","TWN":"趴…趴下！夫人！"},"stage":{"bg":"HALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":" 히이……!","JPN":" ひいっ……！","ENG":"Ahhh...!","TWN":"嗚……！"},"stage":{"bg":"HALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":" ......아파. 너무해.","JPN":" ……痛い、ひどいわ。","ENG":"...That hurt. How rude.","TWN":"……好痛喔，過分。"},"stage":{"bg":"HALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":" 나 몰래 무슨 약을 빨았길래 집단 다이빙을 하나 했더니. 네가 범인인가 보네.","JPN":" 集団自殺なんて、私の知らない間にどんな薬をやったのかと思ったけど。犯人が別にいたとはね？","ENG":"I was wondering what kind of drugs they were on to be jumping as a group like that. Seems like you're the culprit.","TWN":"我還以為他們是偷吸毒，搞得神經不正常才集體跳樓，原來犯人是你。"},"stage":{"bg":"HALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 오, 오지만디아스! 대체 어디 있던 겁니까!","JPN":" お、オジマンディアス！　いったい今までどこにいらしたんですか！","ENG":"O-Ozymandias! Where were you?!","TWN":"奧…奧茲曼迪亞斯！你剛到底在哪裡！"},"stage":{"bg":"HALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":" 들볶지 말아 줄래? 나도 지원 요청 받자마자 패션쇼에서 뛰쳐 나온 거니까.","JPN":" あんまり責め立てないでくれる？　私だって支援要請を受けて、すぐにファッションショーを飛び出してきたんだから。","ENG":"Ugh, enough with the nagging. I ran out of the fashion show as soon as I saw the request for backup.","TWN":"不要追問這麼多好嗎？我也是一收到請求，就立刻從時尚秀衝過來欸。"},"stage":{"bg":"HALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":" VIP 잘 챙겨. 괜히 머리통 날아가지 않게 총은 버려 두고.","JPN":" VIPをしっかり守りなさい。自害させられたくなければ銃は捨てておくことね。","ENG":"Take care of the VIP. And throw away your gun, so you don't shoot yourself.","TWN":"你把VIP顧好，放下槍，免得到時候莫名其妙腦袋開花。"},"stage":{"bg":"HALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":" 그래서, 그림자라……. 직접 상대해 보는 건 꽤 오랜만인데.","JPN":" さて、シャドウか……直接やり合うのは何年ぶりかしら。","ENG":"So, a Shadow... It's been a while since I've fought one myself.","TWN":"暗影嗎……我很久沒跟暗影交手了呢。"},"stage":{"bg":"HALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":" ……시끄럽고 천박한 여자네. 연주는 조용히 감상해 줘.","JPN":" ……うるさくて下品な女ね。演奏中は静かにしてほしいわ。","ENG":"...Such a loud, vulgar woman. Please be a quiet audience.","TWN":"……真是個聒噪又低俗的女人，聽演奏時請保持安靜。"},"stage":{"bg":"HALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":" 글쎄? 그딴 구닥다리 클래식이나 연주하니까 사람들이 못 들어 주는 거 아냐?","JPN":" そう？　そんな古臭いクラシックばかり演奏するから、みんなに聞いてもらえないんじゃない？","ENG":"Well, maybe the others found your old-time classical music insufferable.","TWN":"是我的問題嗎？是你的演奏太老掉牙，才會搞得人家聽不下去吧？"},"stage":{"bg":"HALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":" ………….","JPN":" ……","ENG":"...","TWN":"…………"},"stage":{"bg":"HALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":" 너무해. 너는 반드시 죽여 줄게.","JPN":" ひどいわ。あなたは必ず殺してあげる。","ENG":"That was harsh. I will make sure you do not make it out alive.","TWN":"過分，我一定要讓你死。"},"stage":{"bg":"HALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":" 그 말 후회하게 될 걸.","JPN":" 今の言葉、後悔するわよ。","ENG":"You're gonna regret saying that.","TWN":"我會讓你後悔說出這句話。"},"stage":{"bg":"HALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":" 우리 잘난 기사단은 그림자 전문이거든.","JPN":" うちの騎士団って、シャドウ専門なのよね。","ENG":"Our pompous order specializes in dealing with Shadows.","TWN":"我們榮耀的騎士團可是專門對付暗影的呢。"},"stage":{"bg":"HALL","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};